// Build semantic matching prompt using generated profile data as company data
const profileRaw = $('Get Profile').first().json;
const profileData = Array.isArray(profileRaw) ? profileRaw[0] : profileRaw;
const conditionsRaw = $('Get Conditions').first().json;
const definitionsRaw = $('Get Definitions').first().json;

const conditionsArr = Array.isArray(conditionsRaw) ? conditionsRaw : [];
const definitionsArr = Array.isArray(definitionsRaw) ? definitionsRaw : [];

// Format gate conditions for prompt
const formattedConditions = conditionsArr.map(g => ({
  id: g.id,
  number: g.condition_number,
  text: g.condition_text,
  type: g.condition_type,
  is_mandatory: g.is_mandatory,
  required_amount: g.required_amount,
  required_count: g.required_count,
  required_years: g.required_years,
  resolved_requirement: g.resolved_requirement
}));

// Use generated profile data as if it were a real company
const projects = (profileData.generated_projects || []).map(p => ({
  name: p.project_name,
  client: p.client_name,
  client_type: p.client_type,
  start_date: p.start_date,
  end_date: p.end_date,
  total_value: p.total_value,
  type: p.project_type,
  category: p.category,
  technologies: p.technologies,
  role_type: p.role_type,
  description: p.description || ''
}));

const financials = profileData.generated_financials || [];

const certifications = (profileData.generated_certifications || []).map(c => ({
  type: c.cert_type,
  name: c.cert_name,
  issuing_body: c.issuing_body,
  valid_from: c.valid_from,
  valid_until: c.valid_until
}));

const personnel = (profileData.generated_personnel || []).map(p => ({
  name: p.full_name,
  role: p.role,
  education: p.education,
  years_experience: p.years_experience,
  certifications: p.professional_certifications
}));

// System prompt - Semantic matching expert
const systemPrompt = `אתה מומחה להתאמת פרופילי חברות מול תנאי סף במכרזים ישראליים.

## עקרון מרכזי:
כל בדיקה חייבת להתבסס על **ההגדרות הספציפיות של המכרז**, לא על הבנה כללית.

## כללי ברזל:
1. **שם הפרויקט אינו ראיה** - בדוק תוכן, לא כותרת
2. **הגדרת המכרז קודמת לכל** - אם המכרז מגדיר "תחבורתי" = תח"צ בלבד, כביש ≠ תחבורתי
3. **ערכי סף הם מוחלטים** - 9.9M < 10M = לא עומד
4. **טווחי זמן מדויקים** - יום אחד מחוץ לטווח = לא עומד
5. **הסבר כל החלטה** - כל כן/לא חייב נימוק
6. **זהה מניפולציות** - שמות מטעים, ערכי גבול, תחומים מעורבים
7. **פרשנות כפולה** - תמיד הצג גם מצמצמת וגם מרחיבה

ענה תמיד ב-JSON מובנה.`;

// User prompt - Full semantic matching
const userPrompt = `בצע התאמה סמנטית מלאה בין פרופיל חברה לתנאי הסף של מכרז.

## הנחיות מרכזיות:
- השתמש בהגדרות המכרז לסיווג כל פרויקט
- אל תסתמך על שמות פרויקטים - בדוק תוכן בלבד
- חפש אי-התאמות ודגלים אדומים
- תן הסבר מפורט בעברית לכל החלטה

## הגדרות המכרז:
${JSON.stringify(definitionsArr, null, 2)}

## תנאי הסף:
${JSON.stringify(formattedConditions, null, 2)}

## פרופיל החברה:

### פרויקטים:
${JSON.stringify(projects, null, 2)}

### נתונים פיננסיים:
${JSON.stringify(financials, null, 2)}

### הסמכות:
${JSON.stringify(certifications, null, 2)}

### אנשי מפתח:
${JSON.stringify(personnel, null, 2)}

## פלט נדרש (JSON):
{
  "matching_results": [
    {
      "condition_id": "UUID",
      "condition_number": "string",
      "condition_text": "string",
      "status": "MEETS | PARTIALLY_MEETS | DOES_NOT_MEET | UNKNOWN",
      "confidence": 0.0,
      "matching_assets": [
        {
          "asset_type": "PROJECT | FINANCIAL | CERTIFICATION | PERSONNEL",
          "asset_name": "string",
          "match_status": "FULL | PARTIAL | NONE",
          "classification": "string",
          "adversarial_flags": [
            {
              "flag_type": "MISLEADING_NAME | BOUNDARY_VALUE | WRONG_DOMAIN | OUT_OF_RANGE | AMBIGUOUS",
              "description": "string",
              "severity": "HIGH | MEDIUM | LOW"
            }
          ],
          "overall_reasoning": "string"
        }
      ],
      "gap_analysis": {
        "has_gap": true,
        "gap_description": "string"
      },
      "explanation_hebrew": "string"
    }
  ],
  "overall_summary": {
    "total_conditions": 0,
    "meets_count": 0,
    "does_not_meet_count": 0,
    "overall_eligibility": "ELIGIBLE | NOT_ELIGIBLE | CONDITIONAL",
    "blocking_conditions": [],
    "executive_summary_hebrew": "string"
  }
}`;

return [{ json: { systemPrompt, userMessage: userPrompt } }];

// Parse Claude matching response and compare with expected results
const claudeResponse = $('Call Claude').first().json;
const text = claudeResponse.content[0].text;
const profileRaw = $('Get Profile').first().json;
const profileData = Array.isArray(profileRaw) ? profileRaw[0] : profileRaw;

// Extract JSON from Claude response
let matchResult;
const codeBlockMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
if (codeBlockMatch) {
  try { matchResult = JSON.parse(codeBlockMatch[1].trim()); } catch(e) { /* continue */ }
}
if (!matchResult) {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try { matchResult = JSON.parse(jsonMatch[0]); } catch(e) { /* continue */ }
  }
}
if (!matchResult) {
  throw new Error('No valid JSON found in Claude matching response');
}

// Compare expected vs actual
const expected = profileData.expected_result || {};
const actual = matchResult.overall_summary || {};
const testPassed = expected.overall_eligibility === actual.overall_eligibility;

// Build test result
const testResult = {
  test_passed: testPassed,
  profile_id: profileData.id,
  profile_type: profileData.profile_type,
  expected_eligibility: expected.overall_eligibility,
  actual_eligibility: actual.overall_eligibility,
  matching_results: matchResult.matching_results || [],
  overall_summary: actual,
  adversarial_alerts: actual.adversarial_alerts || [],
  executive_summary: actual.executive_summary_hebrew || ''
};

return [{ json: testResult }];
